// Normalize Segment track/identify/page event
const body = $input.item.json.body ?? $input.item.json;

const eventType = body.type || 'track'; // track | identify | page
const event = body.event || body.name || 'unknown';
const userId = body.userId || body.anonymousId || '';
const email = body.traits?.email || body.context?.traits?.email || body.properties?.email || '';
const properties = body.properties || {};
const traits = body.traits || body.context?.traits || {};

// High-value product signals that indicate upgrade intent
const HIGH_INTENT_EVENTS = [
  'upgrade_clicked', 'pricing_viewed', 'billing_viewed',
  'export_triggered', 'api_key_created', 'team_invite_sent',
  'integration_connected', 'limit_reached', 'feature_gate_hit'
];

// Activation signals
const ACTIVATION_EVENTS = [
  'onboarding_completed', 'first_project_created', 'first_export',
  'first_integration', 'key_action_completed'
];

const isHighIntent = HIGH_INTENT_EVENTS.includes(event);
const isActivation = ACTIVATION_EVENTS.includes(event);

// Base signal score
const EVENT_SCORES = {
  'upgrade_clicked': 90, 'pricing_viewed': 60, 'billing_viewed': 55,
  'export_triggered': 45, 'api_key_created': 50, 'team_invite_sent': 65,
  'integration_connected': 55, 'limit_reached': 80, 'feature_gate_hit': 75,
  'onboarding_completed': 40, 'first_project_created': 30,
  'first_export': 35, 'key_action_completed': 45
};

const signalScore = EVENT_SCORES[event] || 10;

return [{
  json: {
    event_type: eventType,
    event_name: event,
    user_id: userId,
    email,
    properties,
    traits,
    signal_score: signalScore,
    is_high_intent: isHighIntent,
    is_activation: isActivation,
    received_at: new Date().toISOString()
  }
}];

const segEvent = $('Parse Segment Event').item.json;
const attioContact = $('Get Contact from Attio').item.json;
const segProfile = $input.item.json;

const contact = attioContact?.data || {};
const attrs = contact?.values || {};

const profileTraits = segProfile?.data?.[0]?.traits || {};

return [{
  json: {
    // Identity
    email: segEvent.email,
    user_id: segEvent.user_id,
    first_name: attrs.first_name?.[0]?.value || profileTraits.firstName || '',
    last_name: attrs.last_name?.[0]?.value || profileTraits.lastName || '',
    company: attrs.company?.[0]?.referenced_object?.values?.name?.[0]?.value || profileTraits.company || '',
    job_title: attrs.job_title?.[0]?.value || profileTraits.title || '',
    // Attio CRM state
    attio_contact_id: contact.id?.record_id || null,
    attio_stage: attrs.stage?.[0]?.value || 'unknown',
    attio_plan: attrs.plan?.[0]?.value || 'free',
    attio_mrr: parseFloat(attrs.mrr?.[0]?.value || 0),
    attio_owner_id: attrs.owner?.[0]?.referenced_actor?.id || null,
    pql_score: parseFloat(attrs.pql_score?.[0]?.value || 0),
    // Segment profile
    total_events_30d: profileTraits.total_events_30d || 0,
    features_used: profileTraits.features_used || 0,
    last_seen_at: profileTraits.last_seen_at || null,
    // Current signal
    event_name: segEvent.event_name,
    signal_score: segEvent.signal_score,
    is_high_intent: segEvent.is_high_intent,
    is_activation: segEvent.is_activation,
    event_properties: segEvent.properties
  }
}];

const raw = $input.item.json?.content?.[0]?.text ?? '';
const ctx = $('Merge PQL Context').item.json;
let ai;
try {
  ai = JSON.parse(raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
