const body = $input.item.json.body ?? $input.item.json;
const topic = body.topic || '';
const data = body.data?.item || {};

// Extract conversation details
const conversationId = data.id || '';
const contact = data.contacts?.contacts?.[0] || {};
const email = contact.email || data.source?.author?.email || '';
const contactId = contact.id || '';

// Get conversation parts/messages
const parts = data.conversation_parts?.conversation_parts || [];
const latestMessage = parts[parts.length - 1]?.body || data.source?.body || '';
const allMessages = parts.map(p => p.body || '').filter(Boolean).join(' | ');

// Tags on conversation
const tags = data.tags?.tags?.map(t => t.name) || [];

// CSAT score if present
const csatRating = data.statistics?.csat_rating || null;

// Filter for meaningful signals
const SALES_TAGS = ['sales-inquiry', 'upgrade-question', 'pricing', 'demo-request'];
const CHURN_TAGS = ['cancellation', 'churn-risk', 'unhappy', 'refund-request'];

const hasSalesTag = tags.some(t => SALES_TAGS.includes(t.toLowerCase()));
const hasChurnTag = tags.some(t => CHURN_TAGS.includes(t.toLowerCase()));
const isNewConversation = topic === 'conversation.user.created';
const isTagAdded = topic === 'conversation.tag.created';

if (!hasSalesTag && !hasChurnTag && !isNewConversation) return [];

return [{
  json: {
    topic,
    conversation_id: conversationId,
    email,
    contact_id: contactId,
    latest_message: latestMessage,
    all_messages: allMessages.slice(0, 3000),
    tags,
    has_sales_tag: hasSalesTag,
    has_churn_tag: hasChurnTag,
    csat_rating: csatRating,
    received_at: new Date().toISOString()
  }
}];

const raw = $input.item.json?.content?.[0]?.text ?? '';
const ctx = $('Parse Intercom Conversation').item.json;
let ai;
try {
  ai = JSON.parse(raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch(e) {
  throw new Error('Claude parse failed: ' + raw.slice(0, 200));
}
return [{ json: { ...ctx, ai } }];

const attio = $('Split Trial Users').item.json?.values || {};
const seg = $input.item.json?.traits || {};

const email = attio.email?.[0]?.email_address || '';
const accountAgeDays = Math.floor((Date.now() - new Date(attio.created_at?.[0]?.value || Date.now())) / 86400000);

// PQL scoring model
const sessions = seg.sessions_14d || 0;
const features = seg.features_used || 0;
const keyActions = seg.key_actions_completed || 0;
const invitesSent = seg.invites_sent || 0;
const daysSinceLastSeen = seg.days_since_last_seen || 99;

// Weighted score
const activationScore = Math.min(30, keyActions * 10);
const depthScore = Math.min(25, features * 5);
const breadthScore = Math.min(20, sessions * 2);
const viralScore = Math.min(15, invitesSent * 5);
const recencyScore = daysSinceLastSeen <= 3 ? 10 : daysSinceLastSeen <= 7 ? 6 : daysSinceLastSeen <= 14 ? 3 : 0;

const pqlScore = activationScore + depthScore + breadthScore + viralScore + recencyScore;

// Classify
let pqlTier;
if (pqlScore >= 70) pqlTier = 'hot';
else if (pqlScore >= 40) pqlTier = 'warm';
else pqlTier = 'cold';

// Trial expiry check
const trialEndsAt = attio.trial_ends_at?.[0]?.value || null;
const daysUntilExpiry = trialEndsAt
  ? Math.floor((new Date(trialEndsAt) - Date.now()) / 86400000)
  : null;

const isTrialExpiringSoon = daysUntilExpiry !== null && daysUntilExpiry <= 3 && daysUntilExpiry >= 0;

return [{
  json: {
    email,
    attio_contact_id: $('Split Trial Users').item.json?.id?.record_id || null,
    first_name: attio.first_name?.[0]?.value || '',
    company: attio.company?.[0]?.referenced_object?.values?.name?.[0]?.value || '',
    account_age_days: accountAgeDays,
    pql_score: pqlScore,
    pql_tier: pqlTier,
    activation_score: activationScore,
    depth_score: depthScore,
    sessions_14d: sessions,
    features_used: features,
    key_actions: keyActions,
    days_since_last_seen: daysSinceLastSeen,
    trial_ends_at: trialEndsAt,
    days_until_expiry: daysUntilExpiry,
    is_trial_expiring_soon: isTrialExpiringSoon,
    should_enroll_lemlist: pqlScore >= 70,
    should_reengage: daysSinceLastSeen > 14 && pqlScore < 30
  }
}];
